SELECT f.*, u.username as follower_username, u.nickname as follower_nickname, u.avatar as follower_avatar
FROM follow f
JOIN user u ON f.follower_id = u.id
WHERE f.following_id = #{userId}
ORDER BY f.created_at DESC
LIMIT #{offset}, #{limit}

